SELECT n.id, n.user_id, n.topic_id, t.topic_name, n.title, n.description, n.storage_type, n.status, n.missing_info_mask, n.missing_count, n.md_file_size, n.create_time, n.update_time FROM biz_note n LEFT JOIN biz_topic t ON t.id = n.topic_id
n.status != 8 AND n.user_id = #{userId} AND n.topic_id = #{topicId} AND n.title LIKE CONCAT('%', #{title}, '%') AND n.status = #{status}
ORDER BY n.create_time DESC
